import{_ as t,o as r,c as s,a2 as n}from"./chunks/framework.DvFsUg-r.js";const p=JSON.parse('{"title":"플랫폼 관리 기능 이관","description":"","frontmatter":{"title":"플랫폼 관리 기능 이관","feature_id":"004","status":"done","created":"2026-05-30 22:13 (KST)","updated":"2026-05-31 15:20 (KST)","date":"2026-05-30T00:00:00.000Z","tags":["agent","platform","migration","admin","rbac","audit"]},"headers":[],"relativePath":"specs/004-platform-admin-migration/spec.md","filePath":"specs/004-platform-admin-migration/spec.md","lastUpdated":null}'),e={name:"specs/004-platform-admin-migration/spec.md"};function i(a,o,l,g,c,d){return r(),s("div",null,[...o[0]||(o[0]=[n('<h1 id="spec-플랫폼-관리-기능-이관-clear-platform-→-에이전트-앱" tabindex="-1">Spec: 플랫폼 관리 기능 이관 (Clear Platform → 에이전트 앱) <a class="header-anchor" href="#spec-플랫폼-관리-기능-이관-clear-platform-→-에이전트-앱" aria-label="Permalink to &quot;Spec: 플랫폼 관리 기능 이관 (Clear Platform → 에이전트 앱)&quot;">​</a></h1><h2 id="why-문제-목적" tabindex="-1">Why (문제 / 목적) <a class="header-anchor" href="#why-문제-목적" aria-label="Permalink to &quot;Why (문제 / 목적)&quot;">​</a></h2><p>에이전트 앱(<code>app/</code>)은 현재 langgraph4j 그래프 실행과 정적 데모만 갖춘 최소 서비스다. 실사용 시스템이 되려면 <strong>누가 로그인하고, 무엇을 볼 수 있고, 어떤 일을 했는지</strong>를 다룰 수 있어야 한다.</p><p>기존 사내 플랫폼(<code>C:/ax/lego</code>, &quot;Clear Platform&quot;)에는 인증·권한·코드·다국어· 메일·결재·감사 등 <strong>검증된 엔터프라이즈 관리 기능</strong>이 이미 구현돼 있다. 이를 처음부터 다시 만들지 않고 에이전트 앱으로 <strong>이관(migration)</strong> 하여, 에이전트 기능이 그 위에서 동작할 수 있는 공통 운영 기반을 확보한다.</p><p>이관 대상은 <strong>운영/관리 기반(foundation) 22개 기능</strong>으로, 원본의 불량분석 도메인(Defect)·AI/RAG·Spring Batch 파이프라인은 <strong>포함하지 않는다</strong>.</p><h2 id="what-범위" tabindex="-1">What (범위) <a class="header-anchor" href="#what-범위" aria-label="Permalink to &quot;What (범위)&quot;">​</a></h2><h3 id="포함-—-이관-대상-기능-22" tabindex="-1">포함 — 이관 대상 기능 (22) <a class="header-anchor" href="#포함-—-이관-대상-기능-22" aria-label="Permalink to &quot;포함 — 이관 대상 기능 (22)&quot;">​</a></h3><p><strong>A. 인증</strong></p><ol><li><strong>로그인</strong> — 사용자 인증, 세션/토큰 발급·갱신·로그아웃</li></ol><p><strong>B. 시스템 관리</strong> 2. <strong>메뉴 관리</strong> — 메뉴 트리(그룹/하위) 등록·수정·정렬·삭제 3. <strong>공통코드 관리</strong> — 코드 그룹/코드 항목 CRUD, 조회 캐싱 4. <strong>다국어 메시지</strong> — 메시지 키별 다국어 문구 관리, 언어 선택 5. <strong>시스템 설정</strong> — 키-값 기반 전역 환경설정 관리</p><p><strong>C. 조직 / 사용자 / 권한 (RBAC)</strong> 6. <strong>부서 관리</strong> — 조직/부서 계층 CRUD 7. <strong>사용자 관리</strong> — 사용자 등록·수정·비활성화, 부서·역할 배정 8. <strong>역할 관리</strong> — 역할 CRUD, 역할-권한 매핑 9. <strong>메뉴 권한</strong> — 역할별 메뉴 접근 권한(보기/실행 등) 설정</p><p><strong>D. 메일</strong> 10. <strong>메일 양식</strong> — 메일 템플릿 등록·수정 (제목/본문/변수) 11. <strong>메일 발송 현황</strong> — 발송 이력·상태(성공/실패/대기) 조회</p><p><strong>E. 결재</strong> 12. <strong>결재 양식</strong> — 결재 문서 양식·결재선 정의 13. <strong>결재 목록</strong> — 내 결재/상신/수신 문서 목록 및 처리(승인/반려) 14. <strong>결재 모니터링</strong> — 진행 중 결재 현황·지연 모니터링</p><p><strong>F. 권한 신청</strong> 15. <strong>권한 신청</strong> — 사용자의 권한 요청 → 승인 워크플로우</p><p><strong>G. 이력 관리 (감사 추적)</strong> 16. <strong>로그인 이력</strong> — 로그인 성공/실패 기록 17. <strong>REST API 이력</strong> — API 호출 요청/응답 기록 18. <strong>SQL 실행 이력</strong> — 데이터 접근 쿼리 실행 기록 19. <strong>예외 이력</strong> — 서버 예외/오류 기록 20. <strong>데이터 변경 이력</strong> — 데이터 생성/수정/삭제 전후 값 기록 21. <strong>파일 이력</strong> — 파일 업로드/다운로드/삭제 기록 22. <strong>메뉴 접근 이력</strong> — 사용자별 메뉴 접근 기록</p><h3 id="제외-non-goals" tabindex="-1">제외 (Non-goals) <a class="header-anchor" href="#제외-non-goals" aria-label="Permalink to &quot;제외 (Non-goals)&quot;">​</a></h3><ul><li>원본의 <strong>불량분석 도메인(Defect/Evidence)</strong>, <strong>AI/RAG 채팅·임베딩·벡터검색</strong>, <strong>Spring Batch 파이프라인(설비변경점·이상랏)</strong>, <strong>용어사전(게시판)</strong>, <strong>대시보드 통계</strong>, <strong>알림(WebSocket)</strong> — 이번 이관 범위 밖.</li><li>기존 에이전트 그래프 토폴로지·관측성의 변경(본 기능은 운영 기반 추가이며 에이전트 동작 자체를 바꾸지 않는다).</li><li>원본과의 <strong>데이터 마이그레이션</strong>(기존 운영 데이터를 옮겨오는 작업)은 범위 밖. 이관은 <em>기능/스키마</em> 이관이며, 초기 시드(관리자·기본 메뉴/코드) 수준만 포함.</li></ul><h2 id="clarifications" tabindex="-1">Clarifications <a class="header-anchor" href="#clarifications" aria-label="Permalink to &quot;Clarifications&quot;">​</a></h2><h3 id="session-2026-05-30" tabindex="-1">Session 2026-05-30 <a class="header-anchor" href="#session-2026-05-30" aria-label="Permalink to &quot;Session 2026-05-30&quot;">​</a></h3><ul><li>Q: 데이터 저장소를 무엇으로 확정할까요? → A: <strong>Oracle 유지</strong> (소스와 동일하게 Oracle 21c + MyBatis 매퍼로 이관; 운영 DB 연결 전제)</li><li>Q: 이번 이관의 표면(surface)을 어디까지로 할까요? → A: <strong>백엔드(API·서비스·데이터·감사) 전체 + VuGrid 기반 대표 목록/조회 데모</strong> (전체 Vue 관리자 화면 완전 이식은 후속 비목표)</li><li>Q: 결재 및 권한 신청의 워크플로우 깊이는? → A: <strong>다단계 결재선</strong> (순차 다단계 승인선 지원)</li><li>Q: 감사 이력(7종)의 보존 기간 정책은? → A: <strong>1년 보존 후 정리</strong> (1년 경과분 아카이브/삭제; 이력은 보존 기간 내 append-only)</li></ul><h2 id="user-scenarios" tabindex="-1">User Scenarios <a class="header-anchor" href="#user-scenarios" aria-label="Permalink to &quot;User Scenarios&quot;">​</a></h2><ol><li><strong>관리자 로그인 &amp; 접근 제어</strong> <em>(US1·P1)</em>: 관리자로서 자격증명으로 로그인해, 내 역할에 허용된 관리 메뉴만 보이고 접근할 수 있어, 권한 없는 기능이 노출되지 않는다.</li><li><strong>사용자/역할/권한 운영</strong> <em>(US2·P1)</em>: 시스템 관리자로서 부서·사용자·역할을 만들고 역할에 메뉴 권한을 매핑해, 신규 입사자가 적절한 화면만 사용하게 한다.</li><li><strong>공통코드·다국어 관리</strong> <em>(US3·P2)</em>: 운영 담당자로서 공통코드와 다국어 메시지를 화면에서 바꿔, 코드 배포 없이 드롭다운 값과 화면 문구를 갱신한다.</li><li><strong>권한 신청 → 승인</strong> <em>(US6·P3)</em>: 일반 사용자로서 필요한 권한을 신청하고, 승인자가 결재로 승인하면 해당 권한이 부여된다.</li><li><strong>결재 처리</strong> <em>(US5·P2)</em>: 기안자가 결재 양식으로 문서를 상신하고, 결재선의 승인자가 목록에서 승인/반려하며, 관리자는 진행 현황을 모니터링한다.</li><li><strong>메일 발송 &amp; 추적</strong> <em>(US7·P3)</em>: 운영자로서 메일 양식으로 안내 메일을 보내고, 발송 현황에서 성공/실패를 확인한다.</li><li><strong>감사 추적</strong> <em>(US4·P2)</em>: 보안 담당자로서 누가 언제 로그인/메뉴 접근/데이터 변경을 했는지, 어떤 API·SQL·예외·파일 작업이 있었는지 이력에서 조회·검색한다.</li></ol><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="공통-cross-cutting" tabindex="-1">공통 (Cross-cutting) <a class="header-anchor" href="#공통-cross-cutting" aria-label="Permalink to &quot;공통 (Cross-cutting)&quot;">​</a></h3><ul><li><strong>FR-1 (인증 필수)</strong>: 로그인·공개 엔드포인트를 제외한 모든 관리 기능은 인증된 사용자만 접근할 수 있어야 한다.</li><li><strong>FR-2 (권한 기반 접근)</strong>: 각 기능/메뉴 접근은 사용자의 역할에 매핑된 권한으로 통제되어야 하며, 권한이 없으면 거부(403 상당)되어야 한다.</li><li><strong>FR-3 (목록 표준)</strong>: 모든 목록 조회는 키워드 검색 + 페이지네이션을 지원해야 한다.</li><li><strong>FR-4 (일관 응답)</strong>: 모든 기능은 성공/실패·코드·메시지·데이터를 담은 일관된 응답 형식을 제공해야 한다.</li><li><strong>FR-5 (감사 자동 기록)</strong>: 생성/수정/삭제 등 상태 변경 동작은 행위자·시각· 대상과 함께 자동으로 이력에 남아야 한다.</li></ul><h3 id="기능별-per-feature" tabindex="-1">기능별 (Per-feature) <a class="header-anchor" href="#기능별-per-feature" aria-label="Permalink to &quot;기능별 (Per-feature)&quot;">​</a></h3><ul><li><strong>FR-6 (로그인)</strong>: 시스템은 자격증명 검증 후 인증 토큰을 발급하고, 만료 시 갱신, 로그아웃 시 무효화할 수 있어야 한다. 실패는 로그인 이력에 기록된다.</li><li><strong>FR-7 (메뉴 관리)</strong>: 관리자는 계층형 메뉴(그룹/하위)를 등록·수정·정렬·삭제할 수 있어야 하고, 변경은 사용자 화면 네비게이션에 반영되어야 한다.</li><li><strong>FR-8 (공통코드)</strong>: 관리자는 코드 그룹과 그 하위 코드 항목을 CRUD 할 수 있어야 하고, 다른 기능은 코드 그룹으로 코드 목록을 조회할 수 있어야 한다.</li><li><strong>FR-9 (다국어 메시지)</strong>: 관리자는 메시지 키별로 언어별 문구를 관리할 수 있어야 하고, 화면은 선택된 언어의 문구를 표시해야 한다.</li><li><strong>FR-10 (시스템 설정)</strong>: 관리자는 전역 설정을 키-값으로 조회·변경할 수 있어야 한다.</li><li><strong>FR-11 (부서 관리)</strong>: 관리자는 부서 계층을 CRUD 할 수 있어야 하고, 사용자는 부서에 소속될 수 있어야 한다.</li><li><strong>FR-12 (사용자 관리)</strong>: 관리자는 사용자를 등록·수정·비활성화하고, 부서·역할을 배정하며, 비밀번호를 <strong>초기화</strong>할 수 있어야 한다(관리자 초기화는 사용자 수정 경로의 일부, 본인 비밀번호 변경은 별도 경로).</li><li><strong>FR-13 (역할 관리)</strong>: 관리자는 역할을 CRUD 하고, 역할에 권한을 부여/회수할 수 있어야 한다.</li><li><strong>FR-14 (메뉴 권한)</strong>: 관리자는 역할별로 메뉴 접근 권한을 설정할 수 있어야 하고, 이는 FR-2의 접근 통제에 사용되어야 한다.</li><li><strong>FR-15 (메일 양식)</strong>: 관리자는 변수 치환을 포함한 메일 템플릿을 CRUD 할 수 있어야 한다.</li><li><strong>FR-16 (메일 발송 현황)</strong>: 시스템은 메일 발송 시도와 결과(성공/실패/대기)를 기록하고, 운영자는 이를 조회·재발송 시도할 수 있어야 한다. <strong>(본 범위: 발송 시도·결과 기록·재발송 진입점까지. 실 SMTP 전송 연동은 운영 설정값으로 분리.)</strong></li><li><strong>FR-17 (결재 양식)</strong>: 관리자는 결재 문서 양식과 <strong>다단계(순차) 결재선</strong>을 정의할 수 있어야 한다. 결재선은 단계(순서)별 승인자를 가진다.</li><li><strong>FR-18 (결재 목록·처리)</strong>: 사용자는 상신/수신 결재를 목록으로 보고 승인/반려할 수 있어야 하며, <strong>현재 단계 승인 시 다음 단계로 진행</strong>하고 어느 단계든 반려 시 종료되는 단계별 상태 전이가 기록되어야 한다.</li><li><strong>FR-19 (결재 모니터링)</strong>: 관리자는 진행 중 결재와 <strong>지연 건</strong>을 현황으로 볼 수 있어야 한다. 지연 기준은 <strong>양식별 처리기한(SLA)</strong> 초과로 정의하며, 미설정 시 시스템 설정의 기본 처리기한을 따른다.</li><li><strong>FR-20 (권한 신청)</strong>: 사용자는 권한을 신청하고, 승인되면 해당 권한(역할/메뉴)이 반영되어야 한다.</li><li><strong>FR-21~27 (이력 조회)</strong>: 시스템은 로그인·REST API·SQL 실행·예외·데이터 변경· 파일·메뉴 접근 이력을 각각 기록하고, 관리자는 기간·사용자·키워드 등으로 검색·조회할 수 있어야 한다. 이력은 변경 불가(append-only)이며, <strong>1년 보존 후 정리(아카이브/삭제)</strong> 된다.</li></ul><h2 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h2><blockquote><p>구체 스키마는 plan/ data-model 에서 확정. 여기서는 개념 엔터티만.</p></blockquote><ul><li><strong>User(사용자)</strong>: 자격증명, 상태(활성/비활성), 소속 부서, 배정 역할.</li><li><strong>Role(역할)</strong> / <strong>Permission(권한)</strong>: 역할-권한 N:M.</li><li><strong>Menu(메뉴)</strong>: 계층 구조, 역할별 접근 권한.</li><li><strong>Department(부서)</strong>: 계층 조직.</li><li><strong>CodeGroup / Code(공통코드)</strong>: 그룹-항목 1:N.</li><li><strong>Message(다국어 메시지)</strong>: 키 + 언어별 문구.</li><li><strong>SystemSetting(시스템 설정)</strong>: 키-값.</li><li><strong>MailTemplate / MailLog(메일)</strong>: 양식 + 발송 이력.</li><li><strong>ApprovalForm / ApprovalDocument / ApprovalLine(결재)</strong>: 양식·문서·결재선·상태. ApprovalLine 은 <strong>단계(순서) + 단계별 승인자 + 단계 상태</strong>를 갖는 다단계 구조.</li><li><strong>PermissionRequest(권한 신청)</strong>: 신청자·요청 권한·상태.</li><li><strong>AuditLog 계열(이력)</strong>: 로그인/REST/SQL/예외/데이터변경/파일/메뉴접근 — 공통 필드(행위자·시각·IP·대상)에 유형별 상세. append-only.</li></ul><h2 id="contracts-api-그래프-인터페이스" tabindex="-1">Contracts (API / 그래프 인터페이스) <a class="header-anchor" href="#contracts-api-그래프-인터페이스" aria-label="Permalink to &quot;Contracts (API / 그래프 인터페이스)&quot;">​</a></h2><ul><li><strong>API 스타일</strong>: 기능별 REST 리소스. 공통 CRUD 패턴 <code>GET /…(목록·페이징)</code>, <code>GET /…/{id}</code>, <code>POST /…</code>, <code>PUT /…/{id}</code>, <code>DELETE /…/{id}</code>. 인증은 <code>로그인</code>이 토큰 발급, 이후 요청은 토큰 인증. (구체 경로·스키마는 plan 단계의 Contracts 에서 확정.)</li><li><strong>Graph nodes / edges</strong>: 해당 없음(N/A). 본 기능은 langgraph4j 그래프 토폴로지를 변경하지 않는 <strong>운영 기반 이관</strong>이다. (003 과 동일하게 헌법 원칙 3·4 는 N/A로 plan 에서 명시.)</li></ul><h2 id="assumptions-정보-기반-결정-—-plan-clarify-에서-확정-가능" tabindex="-1">Assumptions (정보 기반 결정 — plan/clarify 에서 확정 가능) <a class="header-anchor" href="#assumptions-정보-기반-결정-—-plan-clarify-에서-확정-가능" aria-label="Permalink to &quot;Assumptions (정보 기반 결정 — plan/clarify 에서 확정 가능)&quot;">​</a></h2><blockquote><p>아래는 차단성 질문 대신 합리적 기본값으로 결정한 사항이다. 변경이 필요하면 <code>/speckit-clarify</code> 또는 plan 단계에서 조정한다.</p></blockquote><ul><li><strong>A1 (이관 충실도)</strong>: 동작·기능은 보존하되 <strong>타겟 앱 규약에 맞게 적응 이식</strong>한다 (패키지 <code>com.example.agent</code>, Java 21, Spring Boot 4, Gradle). 원본의 1:1 소스 복제는 목표가 아니다.</li><li><strong>A2 (이관 표면)</strong> — <em>Clarified 2026-05-30</em>: 1차 목표는 <strong>백엔드 기능(API·서비스·데이터·감사)</strong> 이관이다. 관리자 UI 는 003 의 방향(에이전트 앱 = 정적 리소스 + 최소 데모)과 일관되게, 이미 반입된 <strong>VuGrid 기반 목록/조회 데모</strong> 수준으로 제공한다. 전체 Vue/Vuetify 관리자 화면의 완전 이식은 별도 후속 기능으로 둔다(이번 범위의 명시적 비목표).</li><li><strong>A3 (데이터 저장소)</strong> — <em>Clarified 2026-05-30</em>: 소스와 동일하게 <strong>Oracle 21c + MyBatis 매퍼</strong>로 이관하며, 운영 Oracle 연결을 전제한다. 스키마는 마이그레이션 도구(Liquibase 상당)로 관리한다. 테스트는 Oracle 호환 모드 인메모리 DB를 쓸 수 있으나(원본 H2 테스트 패턴 답습), 런타임 타겟 저장소는 Oracle로 확정한다.</li><li><strong>A4 (인증 방식)</strong>: 원본과 동일하게 <strong>토큰 기반(JWT 상당)</strong> 무상태 인증을 유지한다.</li><li><strong>A5 (초기 데이터)</strong>: 관리자 계정·기본 메뉴/역할/공통코드 등 <strong>최소 시드</strong>만 포함한다. 기존 운영 데이터 이행은 비목표(Non-goals 참조).</li><li><strong>A6 (보존 기간)</strong> — <em>Clarified 2026-05-30</em>: 7종 감사 이력은 <strong>1년 보존 후 정리</strong>(아카이브/삭제)한다. 보존 기간 내에는 변경 불가(append-only).</li><li><strong>A7 (파일 관리 스캐폴딩)</strong>: 22개 목록의 &quot;파일 이력&quot;(감사) 생성을 위해 <strong>파일 업로드/다운로드/삭제 최소 기능(SYS_FILE)</strong> 을 함께 포함한다. 완전한 파일관리 화면/기능은 비목표.</li></ul><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li><strong>SC-1</strong>: 22개 이관 기능이 모두 인증된 관리자에게 동작 가능한 형태로 제공된다 (각 기능별 핵심 시나리오 1개 이상 성공).</li><li><strong>SC-2</strong>: 권한 없는 사용자가 권한 밖 기능에 접근하면 100% 거부된다(우회 0건).</li><li><strong>SC-3</strong>: 모든 상태 변경 동작은 누락 없이 해당 이력에 기록된다(샘플 검증 시 기록 누락 0건).</li><li><strong>SC-4</strong>: 관리자는 7종 이력을 기간·사용자 조건으로 검색해 3초 이내에 결과를 확인할 수 있다.</li><li><strong>SC-5</strong>: 공통코드/다국어 문구를 화면에서 변경하면 코드 재배포 없이 사용자 화면에 반영된다.</li><li><strong>SC-6</strong>: 권한 신청 → 승인 → 권한 반영의 전체 흐름이 사람 개입 외 자동으로 완결된다.</li><li><strong>SC-7</strong>: 원본 도메인/AI/배치 기능에 의존하지 않고도 이관 기능만으로 앱이 기동·동작한다(범위 격리 확인).</li><li><strong>SC-8</strong>: 결재 문서는 정의된 다단계 결재선을 따라 단계별로 진행되며, 각 단계 승인/반려가 정확히 기록된다(다단계 시나리오 검증 성공).</li><li><strong>SC-9</strong>: 생성 1년이 지난 감사 이력은 정리 정책에 따라 조회 대상에서 제외되고, 1년 이내 이력은 100% 보존된다.</li></ul><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><ul><li>[ ] (A2) VuGrid 데모를 <strong>몇 개 기능</strong>에 적용할지(전 기능 vs 대표 몇 개) — plan 에서 데모 대상 확정 (plan-level 세부, 비차단).</li></ul><blockquote><p>해소됨(Session 2026-05-30): 데이터 저장소(→ Oracle 유지), 결재 워크플로우 깊이 (→ 다단계 결재선), 감사 이력 보존(→ 1년). 상세는 <code>## Clarifications</code> 참조.</p></blockquote>',40)])])}const h=t(e,[["render",i]]);export{p as __pageData,h as default};
